    echo "  PASS: Error code format visible" | tee -a $LOG
else
    echo "  INFO: Error codes may be hidden in plain mode" | tee -a $LOG
fi

# Test 4: Suggestions shown
echo "Test 4: Suggestions" | tee -a $LOG
if echo "$OUTPUT" | grep -qiE 'suggest|try|run'; then
    echo "  PASS: Suggestions visible" | tee -a $LOG
fi

# Test 5: Piped error output
echo "Test 5: Piped error output clean" | tee -a $LOG
PIPED=$(xf search "nonexistent123" 2>&1 | cat)
if echo "$PIPED" | grep -qP '\x1b\['; then
    echo "  FAIL: ANSI in piped error output" | tee -a $LOG
    exit 1
fi
echo "  PASS: Piped error output clean" | tee -a $LOG

# Test 6: stderr vs stdout separation
